mapper.update:
update course_selection

    status = '已退课'

where id = #{courseSelectionId}

mapper.select:
select cs.id, c.course_name, c.credit, s.name as semester_name, cs.status, cs.score, cs.score_point
from course_selection cs
left join course c on cs.course_id = c.id
left join semester s on cs.semester_id = s.id

    cs.student_id = #{studentId}
    and cs.semester_id = #{semesterId}
    and cs.status = #{status}

order by cs.id desc

select cs.id, cs.course_id, cs.student_id as studentId, stu.name as student_name, c.course_name, c.credit, s.name as semester_name, cs.status, cs.score, cs.score_point
from course_selection cs
         left join course c on cs.course_id = c.id
         left join student stu on cs.student_id = stu.id
         left join semester s on cs.semester_id = s.id

    cs.student_id = #{studentId}
    and cs.course_id = #{courseId}
    and cs.semester_id = #{semesterId}
    and cs.status = #{status}
